2026		--! cl_fix_resize implementation			
2027		function cl_fix_resize (a			: std_logic_vector; 
2028								a_fmt		: FixFormat_t; 
2029								result_fmt	: FixFormat_t; 
2030								round		: FixRound_t	:= Trunc_s; 
2031								saturate	: FixSaturate_t	:= Warn_s) 
2032								return std_logic_vector is
2033			constant DropFracBits_c		: integer := a_fmt.FracBits - result_fmt.FracBits;
2034			constant NeedRound_c		: boolean := round /= Trunc_s and DropFracBits_c > 0;
2035			-- Rounding addition is performed with an additional integer bit (carry bit)
2036			constant CarryBit_c			: boolean := NeedRound_c and saturate /= None_s;
2037			-- It is not clear what this extra bit is for (undocumented)
2038			constant AddSignBit_c		: boolean := ((a_fmt.Signed = false) and (result_fmt.Signed = false) and (saturate /= None_s));
2039			-- Several rounding methods use the largest value smaller than the tie weight ("half").
2040			-- The required integer value is 2**(DropFracBits_c-1)-1, but to support >32 bits, we use unsigned.
2041			function GetHalfMinusDelta return unsigned is
2042			begin
2043				-- If DropFracBits_c = 1, then 2**(DropFracBits_c-1)-1 = 0.
2044				-- If DropFracBits_c < 1, then NeedRound_c = FALSE, so the value is never used (just return 0).
2045				if DropFracBits_c <= 1 then
2046					return "0";
2047				end if;
2048				-- If DropFracBits_c > 1 then 2**(DropFracBits_c-1)-1 = "11...1"
2049				return (DropFracBits_c-2 downto 0 => '1');
2050			end function;
2051			
2052			constant HalfMinusDelta_c	: unsigned := GetHalfMinusDelta;
2053			constant TempFmt_c : FixFormat_t := 
2054				(
2055					Signed		=> a_fmt.Signed or result_fmt.Signed, -- must stay like this!
2056					IntBits		=> max(a_fmt.IntBits + toInteger(CarryBit_c), result_fmt.IntBits) + toInteger(AddSignBit_c), 
2057					FracBits	=> max(a_fmt.FracBits, result_fmt.FracBits)
2058				);
2059			constant TempWidth_c		: positive := cl_fix_width(TempFmt_c);
2060			constant ResultWidth_c		: positive := cl_fix_width(result_fmt);
2061			constant MoreFracBits_c		: natural := TempFmt_c.FracBits - a_fmt.FracBits;
2062			constant CutFracBits_c		: natural := TempFmt_c.FracBits - result_fmt.FracBits;
2063			constant CutIntSignBits_c	: integer := TempWidth_c - (ResultWidth_c+CutFracBits_c);
2064			
2065			variable a_v		: std_logic_vector(a'length-1 downto 0);
2066			variable temp_v		: unsigned(TempWidth_c-1 downto 0);
2067			variable sign_v		: std_logic;
2068			variable result_v	: std_logic_vector(ResultWidth_c-1 downto 0);
2069		begin
2070			-- TODO: Rounding addition could be less wide when result_fmt.IntBits > a_fmt.IntWidth
2071			-- TODO: saturate = Warn_s could use no carry bit for synthesis.
2072			a_v := a;
2073			temp_v := (others => '0');
2074			if a_fmt.Signed then
2075				temp_v(temp_v'high downto MoreFracBits_c) := unsigned(resize(signed(a_v), TempWidth_c-MoreFracBits_c));
2076			else
2077				temp_v(temp_v'high downto MoreFracBits_c) := resize(unsigned(a_v), TempWidth_c-MoreFracBits_c);
2078			end if;
2079			if NeedRound_c then -- rounding required
2080				if a_fmt.Signed then
2081					sign_v := a_v(a_v'high);
2082				else
2083					sign_v := '0';
2084				end if;
2085				case round is
2086					when Trunc_s		=> null;
2087					when NonSymPos_s	=> temp_v(TempWidth_c-1 downto DropFracBits_c-1) := temp_v(TempWidth_c-1 downto DropFracBits_c-1) + 1;
2088					when NonSymNeg_s	=> temp_v := temp_v + HalfMinusDelta_c;
2089					when SymInf_s		=> temp_v := temp_v + HalfMinusDelta_c + ("" & not sign_v);
2090					when SymZero_s		=> temp_v := temp_v + HalfMinusDelta_c + ("" & sign_v);
2091					when ConvEven_s		=>
2092						if DropFracBits_c < a_v'length then
2093							temp_v := temp_v + HalfMinusDelta_c + ("" & a_v(DropFracBits_c));
2094						else
2095							temp_v := temp_v + HalfMinusDelta_c + ("" & sign_v); -- implicit sign extension
2096						end if;
2097					when ConvOdd_s 		=>
2098						if DropFracBits_c < a_v'length then
2099							temp_v := temp_v + HalfMinusDelta_c + ("" & not a_v(DropFracBits_c));
2100						else
2101							temp_v := temp_v + HalfMinusDelta_c + ("" & not sign_v); -- implicit sign extension
2102						end if;
2103				end case;
2104			end if;
2105			if CutIntSignBits_c > 0 and saturate /= None_s then -- saturation required
2106				if result_fmt.Signed then -- signed output
2107					if temp_v(temp_v'high downto temp_v'high-CutIntSignBits_c) /= 0 and 
2108							not temp_v(temp_v'high downto temp_v'high-CutIntSignBits_c) /= 0 then
2109						assert saturate = Sat_s report "cl_fix_resize : Saturation Warning!" severity warning;
2110						if saturate /= Warn_s then
2111							temp_v(temp_v'high-1 downto 0) := (others => not temp_v(temp_v'high));
2112							temp_v(ResultWidth_c+CutFracBits_c-1) := temp_v(temp_v'high);
2113						end if;
2114					end if;
2115				else -- unsigned output
2116					if temp_v(temp_v'high downto temp_v'high-CutIntSignBits_c+1) /= 0 then
2117						assert saturate = Sat_s report "cl_fix_resize : Saturation Warning!" severity warning;
2118						if saturate /= Warn_s then
2119							temp_v := (others => not temp_v(temp_v'high));
2120						end if;
2121					end if;
2122				end if;
2123			end if;
2124			result_v := std_logic_vector(temp_v(ResultWidth_c+CutFracBits_c-1 downto CutFracBits_c));
2125			return result_v;
2126		end;
