2319		--! cl_fix_addsub_internal implementation (internal package use only)
2320		function cl_fix_addsub_internal(	a			: std_logic_vector;
2321											a_fmt		: FixFormat_t; 
2322											b			: std_logic_vector;
2323											b_fmt		: FixFormat_t;
2324											add			: std_logic) return std_logic_vector is
2325			constant IsSigned_c	: boolean := a_fmt.Signed or b_fmt.Signed;
2326			variable result_v	: std_logic_vector(a'range);
2327		begin
2328			-- Synthesis tools may create problems if correct signed/unsigned type
2329			-- is not used for addition.
2330			if to01 (add) = '1' then
2331				if IsSigned_c then
2332					result_v := std_logic_vector (  signed (a) +   signed (b));
2333				else
2334					result_v := std_logic_vector (unsigned (a) + unsigned (b));
2335				end if;
2336			else
2337				if IsSigned_c then
2338					result_v := std_logic_vector (  signed (a) -   signed (b));
2339				else
2340					result_v := std_logic_vector (unsigned (a) - unsigned (b));
2341				end if;
2342			end if;
2343			return result_v;
2344		end function;
