2347		--! cl_fix_add implementation	
2348		function cl_fix_add (	a			: std_logic_vector; 
2349								a_fmt		: FixFormat_t; 
2350								b			: std_logic_vector; 
2351								b_fmt		: FixFormat_t; 
2352								result_fmt	: FixFormat_t; 
2353								round		: FixRound_t	:= Trunc_s; 
2354								saturate	: FixSaturate_t	:= Warn_s) 
2355								return std_logic_vector is
2356			constant CarryBit_c : boolean := -- addition performed with an additional integer bit
2357				result_fmt.IntBits > max (a_fmt.IntBits, b_fmt.IntBits) or (saturate = Sat_s or
2358			-- synthesis translate_off
2359				saturate = Warn_s or
2360			-- synthesis translate_on
2361				saturate = SatWarn_s);
2362				-- TODO: CarryBit in cl_fix_resize not needed in all cases
2363			constant TempFmt_c 	: FixFormat_t := 
2364				(
2365					Signed		=> a_fmt.Signed or b_fmt.Signed,
2366					IntBits		=> max (a_fmt.IntBits, b_fmt.IntBits) + toInteger (CarryBit_c), 
2367					FracBits	=> max (a_fmt.FracBits, b_fmt.FracBits)
2368				);
2369			constant TempWidth_c: positive := cl_fix_width (TempFmt_c);
2370			variable a_v		: std_logic_vector (TempWidth_c-1 downto 0);
2371			variable b_v		: std_logic_vector (TempWidth_c-1 downto 0);
2372			variable temp_v		: std_logic_vector (TempWidth_c-1 downto 0);
2373			variable result_v	: std_logic_vector (cl_fix_width (result_fmt)-1 downto 0);
2374		begin
2375			a_v := cl_fix_resize (a, a_fmt, TempFmt_c, Trunc_s, None_s);
2376			b_v := cl_fix_resize (b, b_fmt, TempFmt_c, Trunc_s, None_s);
2377			temp_v := cl_fix_addsub_internal(a_v, a_fmt, b_v, b_fmt, '1');
2378			result_v := cl_fix_resize (temp_v, TempFmt_c, result_fmt, round, saturate);
2379			return result_v;
2380		end;
