2577		--! cl_fix_mult implementation
2578		function cl_fix_mult (	a			: std_logic_vector; 
2579								a_fmt		: FixFormat_t; 
2580								b			: std_logic_vector; 
2581								b_fmt		: FixFormat_t; 
2582								result_fmt	: FixFormat_t; 
2583								round		: FixRound_t	:= Trunc_s; 
2584								saturate	: FixSaturate_t := Warn_s) 
