2592				);
2593			variable a_v		: std_logic_vector (a'length-1 downto 0);
2594			variable b_v		: std_logic_vector (b'length-1 downto 0);
2595			variable temp_v		: std_logic_vector (cl_fix_width (TempFmt_c)-1 downto 0);
2596			variable result_v	: std_logic_vector (cl_fix_width (result_fmt)-1 downto 0);
2597		begin
2598			a_v := a;
2599			b_v := b;
2600			if a_fmt.Signed then
2601				if b_fmt.Signed then
2602					temp_v := std_logic_vector (signed (a_v) * signed (b_v));
2603				else
2604					temp_v := std_logic_vector (signed (a_v) * ("0" & signed (b_v)));
2605				end if;
2606			else
2607				if b_fmt.Signed then
2608					temp_v := std_logic_vector (("0" & signed (a_v)) * signed (b_v));
2609				else
2610					temp_v := std_logic_vector (unsigned (a_v) * unsigned (b_v));
2611				end if;
2612			end if;
2613			result_v := cl_fix_resize (temp_v, TempFmt_c, result_fmt, round, saturate);
2614			return result_v;
2615		end;
